import asyncio
import websockets

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = []

async def item_transfer(sender, receiver, item):
    if item in sender.inventory:
        sender.inventory.remove(item)
        receiver.inventory.append(item)

async def handle_client(websocket, path):
    player = Player(path)
    await websocket.send("Welcome to the game server!")

    async for message in websocket:
        action, *args = message.split()
        
        if action == "trade":
            sender, receiver, item = args
            await item_transfer(sender, receiver, item)
            await websocket.send(f"Successfully traded {item} to {receiver}")

start_server = websockets.serve(handle_client, "localhost", 8765)
asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()